"""Generated Warcraft III ability-field catalogue.

Sources:
- Warcraft III v2.0 common.j field constants.
- Reforged AbilityMetaData.slk compatibility metadata.
"""

from __future__ import annotations

from dataclasses import dataclass


@dataclass(frozen=True)
class AbilityFieldSpec:
    rawcode: str
    constant_name: str
    value_kind: str
    scope: str
    metadata_type: str
    field_name: str
    category: str
    display_name: str
    use_specific: tuple[str, ...]
    not_specific: tuple[str, ...]
    minimum: int | float | str | None
    maximum: int | float | str | None
    writable: bool

    @property
    def field_id(self) -> int:
        return int.from_bytes(self.rawcode.encode("ascii"), "big")

    @property
    def is_level_field(self) -> bool:
        return self.scope != "field"

    @property
    def runtime_supported(self) -> bool:
        return self.scope in {"field", "level"} and self.value_kind in {"boolean", "integer", "real"}


