ABILITY_FIELD_CATALOG = tuple(AbilityFieldSpec(*row) for row in _ABILITY_FIELD_DATA)
ABILITY_FIELD_BY_KEY = {
    (field.rawcode, field.value_kind, field.scope): field
    for field in ABILITY_FIELD_CATALOG
}
if len(ABILITY_FIELD_BY_KEY) != len(ABILITY_FIELD_CATALOG):
    raise RuntimeError("ability field catalogue contains duplicate runtime keys")


def ability_fields_for_effect_class(effect_class: str) -> tuple[AbilityFieldSpec, ...]:
    effect_class = effect_class.strip()
    return tuple(
        field
        for field in ABILITY_FIELD_CATALOG
        if (not field.use_specific or effect_class in field.use_specific)
        and effect_class not in field.not_specific
    )
